{
  "title": "人工智能发展简史",
  "chapters": [
    {
      "title": "导论：为什么学AI史？",
      "pages": [
        {
          "title": "课程定位与学习目标",
          "bullets": ["理解技术演进背后的逻辑而非罗列年份", "识别周期性起伏中的关键转折点", "建立‘技术-算力-数据-社会’四维分析框架"],
          "notes": "开场提问：‘如果图灵活到今天，他会惊讶什么？’ 引出历史不是线性进步，而是螺旋上升。"
        },
        {
          "title": "AI发展的典型特征",
          "bullets": ["繁荣与寒冬交替出现（约10年周期）", "每次复兴都由新范式+新硬件+新数据驱动", "从专用智能走向通用智能的长期目标未变"],
          "notes": "类比：像潮汐——涨潮带来新工具，退潮留下基础设施；用‘潮汐图’示意各阶段持续时间。"
        }
      ]
    },
    {
      "title": "奠基与幻灭：1950s–1960s",
      "pages": [
        {
          "title": "思想起源：图灵与达特茅斯",
          "bullets": ["1950年《计算机器与智能》提出‘模仿游戏’（图灵测试）", "1956年达特茅斯会议首次定义‘Artificial Intelligence’", "麦卡锡、明斯基、香农、纽厄尔、西蒙等奠基者齐聚"],
          "notes": "强调：这不是技术发布会，而是一场‘命名仪式’——为尚未存在的学科赋予身份。"
        },
        {
          "title": "早期突破与局限",
          "bullets": ["逻辑理论家（LT）：首个自动定理证明程序", "感知机（Perceptron）：首个人工神经网络模型", "但无法解决异或（XOR）问题，被Minsky在1969年批判"],
          "notes": "展示感知机结构简图；指出‘失败’本身催生了后续连接主义复兴——寒冬埋下种子。"
        }
      ]
    },
    {
      "title": "规则时代：1970s–1980s",
      "pages": [
        {
          "title": "专家系统的兴起",
          "bullets": ["MYCIN：用20条规则诊断血液感染，准确率超人类医生", "DENDRAL：解析质谱数据推断分子结构", "XCON：DEC公司配置计算机系统，年省4000万美元"],
          "notes": "对比：MYCIN是学术标杆，XCON是商业验证——说明AI价值需落地场景闭环。"
        },
        {
          "title": "寒冬再临与反思",
          "bullets": ["1973年莱特希尔报告：批评AI‘无通用性、无实用性’", "英国政府终止资助；美国DARPA转向‘实用导向’项目", "知识获取瓶颈暴露：人类专家难于形式化自身经验"],
          "notes": "过渡语：‘当规则写满10万行，维护成本就压垮了创新’——引出下一章的数据驱动转向。"
        }
      ]
    },
    {
      "title": "转向数据：1990s–2000s",
      "pages": [
        {
          "title": "机器学习成为新范式",
          "bullets": ["统计学习取代符号推理：SVM（1995）、随机森林（1997）", "深蓝（1997）：暴力搜索+专用硬件，非学习型AI", "互联网兴起带来海量标注数据（如网页、邮件）"],
          "notes": "澄清误区：深蓝≠深度学习；它是工程奇迹，但不具备泛化能力。"
        },
        {
          "title": "基础设施准备期",
          "bullets": ["开源运动兴起（Linux, Python）降低研究门槛", "GPU尚未用于AI，但图形渲染需求推动并行计算发展", "ImageNet（2009）尚未发布，但小规模数据集（MNIST/CIFAR）已普及"],
          "notes": "提示：这一时期像‘修路’——不显眼，却是2012年爆发的必要条件。"
        }
      ]
    },
    {
      "title": "深度革命：2010s",
      "pages": [
        {
          "title": "AlexNet：引爆点",
          "bullets": ["2012年ImageNet大赛错误率骤降11个百分点", "首次大规模使用ReLU、Dropout、GPU并行训练", "证明深层网络+大数据可突破传统方法天花板"],
          "notes": "展示错误率对比柱状图；强调：不是算法多新颖，而是‘规模+工程’组合拳。"
        },
        {
          "title": "从感知到博弈：AlphaGo",
          "bullets": ["2016年击败李世石：结合蒙特卡洛树搜索+深度策略/价值网络", "围棋状态空间10^170，远超宇宙原子数（10^80）", "标志着AI具备复杂决策与直觉模拟能力"],
          "notes": "举例：第37手‘上帝之手’——说明AI可生成人类未曾构想的策略。"
        }
      ]
    },
    {
      "title": "大模型时代：2020s至今",
      "pages": [
        {
          "title": "ChatGPT：现象级拐点",
          "bullets": ["2022年11月发布，5天破百万用户，2个月破亿", "基于GPT-3.5微调，首次让普通人‘对话即用’", "触发全球企业AI战略重置（微软/谷歌/百度全面跟进）"],
          "notes": "数据对比：iPhone发布后达百万用户用时74天——ChatGPT快15倍。"
        },
        {
          "title": "中国模型生态崛起",
          "bullets": ["文心一言（2023.3）、通义千问（2023.4）、ChatGLM（2023.5）、DeepSeek（2023.12）", "开源策略分化：Qwen-7B轻量易部署，DeepSeek-V2支持128K上下文", "2025年趋势：开源模型性能逼近GPT-4，但推理成本仍高"],
          "notes": "提示：展示各模型发布时间轴；强调‘追赶’背后是中文语料、工程优化、场景适配的三重努力。"
        }
      ]
    },
    {
      "title": "挑战与未来：不止于更大",
      "pages": [
        {
          "title": "当前核心挑战",
          "bullets": ["幻觉（Hallucination）：自信输出错误事实", "能耗问题：训练GPT-3耗电≈130户家庭年用电", "对齐难题（Alignment）：如何让AI目标与人类一致？"],
          "notes": "举例：医疗问答中编造不存在的论文——说明‘可信AI’比‘强大AI’更紧迫。"
        },
        {
          "title": "前沿探索方向",
          "bullets": ["具身智能：机器人+大模型实现物理世界交互", "AI Agent：自主规划-调用工具-迭代修正任务", "小模型革命：Phi-3、TinyLlama在手机端运行"],
          "notes": "结语过渡：‘下一个十年，AI将不再只是‘回答问题’，而是‘解决问题’——而历史告诉我们，每一次跨越都始于对过去的清醒认知。’"
        }
      ]
    }
  ]
}
